    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT timetable_slots_day_of_week_check CHECK (((day_of_week)::text = ANY ((ARRAY['MON'::character varying, 'TUE'::character varying, 'WED'::character varying, 'THU'::character varying, 'FRI'::character varying, 'SAT'::character varying])::text[]))),
    CONSTRAINT timetable_slots_period_no_check CHECK (((period_no >= 1) AND (period_no <= 12)))
);


